// ━━━ HTML Decoding ━━━
function 解码页面(hexStr) {
  const bytes = new Uint8Array(hexStr.match(/../g).map(b => parseInt(b, 16)));
  return new TextDecoder().decode(bytes);
}
const 管理页面 = 解码页面('');
const 订阅页面 = 解码页面('');
const 伪装页面 = 解码页面('');

// ━━━ Utility Functions ━━━
function 生成UUID() { return crypto.randomUUID(); }

function 格式化字节(bytes) {
  if (bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
}

function 剩余天数(expireDate) {
  if (!expireDate) return -1;
  return Math.ceil((new Date(expireDate).getTime() - Date.now()) / 86400000);
}

function 简单哈希(str) {
  let h1 = 0xdeadbeef, h2 = 0x41c6ce57;
  for (let i = 0; i < str.length; i++) {
    const ch = str.charCodeAt(i);
    h1 = Math.imul(h1 ^ ch, 2654435761);
    h2 = Math.imul(h2 ^ ch, 1597334677);
  }
  h1 = Math.imul(h1 ^ (h1 >>> 16), 2246822507);
  h1 ^= Math.imul(h2 ^ (h2 >>> 13), 3266489909);
  h2 = Math.imul(h2 ^ (h2 >>> 16), 2246822507);
  h2 ^= Math.imul(h1 ^ (h1 >>> 13), 3266489909);
  return (4294967296 * (2097151 & h2) + (h1 >>> 0)).toString(16).padStart(16, '0');
}

function 哈希密码(pw) { return 简单哈希(pw); }

function 生成密码(len = 16) {
  const chars = 'ABCDEFGHJKMNPQRSTUVWXYZabcdefghjkmnpqrstuvwxyz23456789!@#$%&*';
  let pw = '';
  const rv = new Uint8Array(len);
  crypto.getRandomValues(rv);
  for (let i = 0; i < len; i++) pw += chars[rv[i] % chars.length];
  return pw;
}

function 数据转UUID(bytes) {
  const hex = Array.from(bytes, b => b.toString(16).padStart(2, '0')).join('');
  return hex.slice(0,8)+'-'+hex.slice(8,12)+'-'+hex.slice(12,16)+'-'+hex.slice(16,20)+'-'+hex.slice(20);
}

function 解析目标地址(data, offset) {
  const addrType = data[offset]; offset++;
  let addr;
  switch (addrType) {
    case 1:
      addr = data[offset] + '.' + data[offset+1] + '.' + data[offset+2] + '.' + data[offset+3];
      offset += 4; break;
    case 2: {
      const dl = data[offset]; offset++;
      addr = new TextDecoder().decode(data.slice(offset, offset + dl));
      offset += dl; break;
    }
    case 3: {
      const parts = [];
      for (let i = 0; i < 8; i++) parts.push(((data[offset+i*2] << 8) | data[offset+i*2+1]).toString(16));
      addr = parts.join(':'); offset += 16; break;
    }
    default: throw new Error('Unknown addr type: ' + addrType);
  }
  const port = (data[offset] << 8) | data[offset+1]; offset += 2;
  return { addr, port, newOffset: offset };
}

function 响应JSON(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status, headers: { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' }
  });
}

const 跨域头 = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type, Authorization',
};

function 时间前(dateStr) {
  const s = Math.floor((Date.now() - new Date(dateStr).getTime()) / 1000);
  if (s < 60) return 'just now';
  if (s < 3600) return Math.floor(s/60) + 'm ago';
  if (s < 86400) return Math.floor(s/3600) + 'h ago';
  if (s < 2592000) return Math.floor(s/86400) + 'd ago';
  return new Date(dateStr).toLocaleDateString();
}

function 解码Base64URL(str) {
  let s = str.replace(/-/g, '+').replace(/_/g, '/');
  while (s.length % 4) s += '=';
  const binary = atob(s);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return bytes;
}

const 禁止缓存 = {
  'Cache-Control': 'no-store, no-cache, must-revalidate, proxy-revalidate, max-age=0',
  'Pragma': 'no-cache',
  'Expires': '0',
  'Surrogate-Control': 'no-store',
};


// ━━━ D1 Database Operations ━━━
async function 获取设置(db, key) {
  const r = await db.prepare('SELECT value FROM settings WHERE key = ?').bind(key).first();
  return r?.value || '';
}

async function 获取所有设置(db) {
  const rows = await db.prepare('SELECT key, value FROM settings').all();
  const s = {};
  for (const row of rows.results) s[row.key] = row.value;
  return {
    protocol: s.protocol || 协议名, transport: s.transport || 'ws',
    path: s.path || '/', host: s.host || '', fingerprint: s.fingerprint || 'chrome',
    sub_name: s.sub_name || 'Usf-Edge', fake_page_url: s.fake_page_url || '',
    admin_path: s.admin_path || 'login', sub_path: s.sub_path || 's',
  };
}

async function 更新设置(db, key, value) {
  await db.prepare('INSERT OR REPLACE INTO settings (key, value) VALUES (?, ?)').bind(key, value).run();
}

async function 通过UUID查找用户(db, uuid) {
  return db.prepare('SELECT * FROM users WHERE uuid = ?').bind(uuid).first();
}

async function 通过名称查找用户(db, name) {
  return db.prepare('SELECT * FROM users WHERE username = ?').bind(name).first();
}

async function 通过ID查找用户(db, id) {
  return db.prepare('SELECT * FROM users WHERE id = ?').bind(id).first();
}

async function 获取所有用户(db) {
  const r = await db.prepare('SELECT * FROM users ORDER BY created_at DESC').all();
  return r.results;
}

async function 创建用户(db, uuid, username, password, volLimit, expireDays, connLimit) {
  const exp = expireDays > 0 ? new Date(Date.now() + expireDays * 86400000).toISOString() : null;
  await db.prepare('INSERT INTO users (uuid, username, password, volume_limit, expire_date, connection_limit) VALUES (?, ?, ?, ?, ?, ?)')
    .bind(uuid, username, password, volLimit, exp, connLimit).run();
  return (await 通过名称查找用户(db, username));
}

async function 更新用户(db, id, updates) {
  const clauses = [], vals = [];
  for (const [k, v] of Object.entries(updates)) {
    clauses.push(k + ' = ?'); vals.push(v);
  }
  if (!clauses.length) return;
  clauses.push("updated_at = datetime('now')"); vals.push(id);
  await db.prepare('UPDATE users SET ' + clauses.join(', ') + ' WHERE id = ?').bind(...vals).run();
}

async function 删除用户(db, id) {
  await db.prepare('DELETE FROM users WHERE id = ?').bind(id).run();
}

async function 获取流量(db, userId) {
  const r = await db.prepare('SELECT COALESCE(SUM(upload),0) as u, COALESCE(SUM(download),0) as d FROM traffic_logs WHERE user_id = ?').bind(userId).first();
  return { upload: r?.u || 0, download: r?.d || 0, total: (r?.u || 0) + (r?.d || 0) };
}

async function 添加流量(db, userId, up, down) {
  if (up === 0 && down === 0) return;
  await db.prepare('INSERT INTO traffic_logs (user_id, upload, download) VALUES (?, ?, ?)').bind(userId, up, down).run();
  await db.prepare("UPDATE users SET volume_used = volume_used + ?, updated_at = datetime('now') WHERE id = ?").bind(up + down, userId).run();
}

async function 重置流量(db, userId) {
  await db.prepare('DELETE FROM traffic_logs WHERE user_id = ?').bind(userId).run();
  await db.prepare("UPDATE users SET volume_used = 0, updated_at = datetime('now') WHERE id = ?").bind(userId).run();
}

async function 添加连接(db, userId, ip, ua) {
  const r = await db.prepare('INSERT INTO active_connections (user_id, ip_address, user_agent) VALUES (?, ?, ?) RETURNING id').bind(userId, ip, ua).first();
  return r?.id || 0;
}

async function 移除连接(db, connId) {
  await db.prepare('DELETE FROM active_connections WHERE id = ?').bind(connId).run();
}

async function 获取连接(db, userId) {
  const r = await db.prepare('SELECT * FROM active_connections WHERE user_id = ? ORDER BY connected_at DESC').bind(userId).all();
  return r.results;
}

async function 计算连接数(db, userId) {
  const r = await db.prepare('SELECT COUNT(*) as c FROM active_connections WHERE user_id = ?').bind(userId).first();
  return r?.c || 0;
}

async function 仪表盘统计(db) {
  const tu = await db.prepare('SELECT COUNT(*) as c FROM users').first();
  const au = await db.prepare("SELECT COUNT(*) as c FROM users WHERE enabled = 1 AND (expire_date IS NULL OR expire_date > datetime('now'))").first();
  const tt = await db.prepare('SELECT COALESCE(SUM(upload + download), 0) as t FROM traffic_logs').first();
  const ac = await db.prepare('SELECT COUNT(*) as c FROM active_connections').first();
  return { total_users: tu?.c || 0, active_users: au?.c || 0, total_traffic: tt?.t || 0, active_connections: ac?.c || 0 };
}

async function 验证用户访问(db, uuid) {
  const user = await 通过UUID查找用户(db, uuid);
  if (!user) return { user: null, allowed: false, reason: 'User not found' };
  if (!user.enabled) return { user, allowed: false, reason: 'Disabled' };
  if (user.expire_date && new Date(user.expire_date) < new Date()) return { user, allowed: false, reason: 'Expired' };
  if (user.volume_limit > 0 && user.volume_used >= user.volume_limit) return { user, allowed: false, reason: 'Volume limit' };
  const cn = await 计算连接数(db, user.id);
  if (user.connection_limit > 0 && cn >= user.connection_limit) return { user, allowed: false, reason: 'Connection limit' };
  return { user, allowed: true, reason: 'OK' };
}


// ━━━ VLESS Protocol Parser ━━━
async function 解析VLESS(数据, 客户端信息, env) {
  if (!数据 || 数据.length < 18) return null;
  if (数据[0] !== 0) return null; // version
  const uuidBytes = 数据.slice(1, 17);
  const 用户UUID = 数据转UUID(uuidBytes);
  const validUser = await 通过UUID查找用户(env.DB, 用户UUID);
  if (!validUser || !validUser.enabled) return null;
  let offset = 17;
  const 附加长度 = 数据[offset]; offset++;
  offset += 附加长度;
  const 命令 = 数据[offset]; offset++;
  const dest = 解析目标地址(数据, offset);
  return { address: dest.addr, port: dest.port, command: 命令, user: validUser, dataOffset: dest.newOffset };
}

// ━━━ Trojan Protocol Parser ━━━
async function 解析Trojan(数据, 客户端信息, env) {
  const 密码长度 = 56;
  const 分隔符 = 2;
  if (!数据 || 数据.length < 密码长度 + 分隔符) return null;
  const passwordHex = new TextDecoder().decode(数据.slice(0, 密码长度));
  if (数据[密码长度] !== 0x0d || 数据[密码长度 + 1] !== 0x0a) return null;
  const user = await 通过UUID查找用户(env.DB, passwordHex);
  if (!user || !user.enabled) return null;
  let offset = 密码长度 + 分隔符;
  const command = 数据[offset]; offset++;
  const dest = 解析目标地址(数据, offset);
  return { address: dest.addr, port: dest.port, command, user, dataOffset: dest.newOffset };
}

// ━━━ WebSocket Proxy Handler ━━━
async function 代理处理(request, env) {
  const settings = await 获取所有设置(env.DB);
  const proto = settings.protocol || 协议名;
  const transport = settings.transport || 'ws';

  const url = new URL(request.url);
  const ua = request.headers.get('User-Agent') || '';
  if (ua.toLowerCase().includes('speedtest') || ua.toLowerCase().includes('speed')) {
    return new Response(null, { status: 444 });
  }

  // XHTTP handling
  if (transport === 'xhttp') {
    return 处理XHTTP(request, env, proto);
  }

  // WebSocket upgrade required
  const upgradeHeader = request.headers.get('Upgrade');
  if (upgradeHeader !== 'websocket') return null;

  const pair = new WebSocketPair();
  const [client, server] = [pair[0], pair[1]];
  server.accept();

  // Parse early data from sec-websocket-protocol
  let 早期数据 = new Uint8Array(0);
  const wsProtocol = request.headers.get('sec-websocket-protocol') || '';
  if (wsProtocol.length > 0) {
    try { 早期数据 = 解码Base64URL(wsProtocol); } catch {}
  }

  let firstMessage = true;

  server.addEventListener('message', async (event) => {
    let 原始数据;
    if (event.data instanceof ArrayBuffer) {
      原始数据 = new Uint8Array(event.data);
    } else return;

    if (firstMessage) {
      firstMessage = false;
    } else {
      // Forward subsequent messages directly to remote
      if (remoteWriter) {
        累计上传 += 原始数据.byteLength;
        try { await remoteWriter.write(原始数据); } catch { server.close(); }
      }
      return;
    }

    // Parse protocol header
    let 目标;
    if (proto === 隧道名) {
      目标 = await 解析Trojan(原始数据, request, env);
    } else {
      目标 = await 解析VLESS(原始数据, request, env);
    }

    if (!目标) { server.close(); return; }

    const 剩余数据 = 原始数据.slice(目标.dataOffset || 0);
    const userId = 目标.user?.id;

    try {
      const remote = connect({ hostname: 目标.address, port: 目标.port });
      let 累计上传 = 0, 累计下载 = 0;

      if (剩余数据.length > 0) {
        累计上传 += 剩余数据.byteLength;
        const w = remote.writable.getWriter();
        await w.write(剩余数据);
        w.releaseLock();
      }

      // Log connection
      if (userId) {
        const ip = request.headers.get('CF-Connecting-IP') || '';
        const 用户UA = request.headers.get('User-Agent') || '';
        添加连接(env.DB, userId, ip, 用户UA).catch(() => {});
      }

      // Remote -> WebSocket
      const remoteReader = remote.readable.getReader();
      (async () => {
        try {
          while (true) {
            const { done, value } = await remoteReader.read();
            if (done) break;
            累计下载 += value.byteLength;
            server.send(value);
          }
        } catch {} finally {
          try { server.close(); } catch {}
        }
      })();

      // Keep writer for subsequent messages
      remoteWriter = remote.writable.getWriter();

      // Traffic logging on close
      server.addEventListener('close', async () => {
        try {
          if (userId && (累计上传 > 0 || 累计下载 > 0)) {
            await 添加流量(env.DB, userId, 累计上传, 累计下载);
          }
          if (userId) {
            // Clean up active connections (best effort)
            const conns = await 获取连接(env.DB, userId);
            for (const c of conns.slice(0, 1)) {
              await 移除连接(env.DB, c.id).catch(() => {});
            }
          }
        } catch {}
      });

    } catch (e) {
      server.close();
    }
  });

  // Send early data if present
  if (早期数据.length > 0) {
    server.send(早期数据);
  }

  return new Response(null, {
    status: 101,
    headers: {
      'Upgrade': 'websocket',
      'Connection': 'Upgrade',
      'Sec-WebSocket-Protocol': wsProtocol,
    },
    webSocket: client,
  });
}

let remoteWriter = null;

// ━━━ XHTTP Handler ━━━
async function 处理XHTTP(request, env, proto) {
  const url = new URL(request.url);
  const seq = parseInt(url.searchParams.get('seq') || '0');

  if (request.method === 'POST' && seq === 0) {
    const body = await request.arrayBuffer();
    const 数据 = new Uint8Array(body);
    let 目标;
    if (proto === 隧道名) {
      目标 = await 解析Trojan(数据, request, env);
    } else {
      目标 = await 解析VLESS(数据, request, env);
    }
    if (!目标) return new Response(null, { status: 400 });

    try {
      const remote = connect({ hostname: 目标.address, port: 目标.port });
      const remaining = 数据.slice(目标.dataOffset || 0);
      if (remaining.length > 0) {
        const writer = remote.writable.getWriter();
        await writer.write(remaining);
        writer.releaseLock();
      }
      return new Response(remote.readable, {
        headers: { 'Content-Type': 'application/octet-stream' }
      });
    } catch {
      return new Response(null, { status: 502 });
    }
  }

  if (request.method === 'PUT') {
    return new Response(null, { status: 200 });
  }

  return new Response(null, { status: 405 });
}


// ━━━ Admin API Handler ━━━
async function 处理管理API(request, env, path) {
  const url = new URL(request.url);

  if (request.method === 'OPTIONS') return new Response(null, { headers: 跨域头 });

  // Public: setup check
  if (path === '/api/auth/setup-check' && request.method === 'GET') {
    const pass = await 获取设置(env.DB, 'admin_pass');
    return 响应JSON({ needs_setup: !pass });
  }

  // Public: first time setup
  if (path === '/api/auth/setup' && request.method === 'POST') {
    const body = await request.json();
    const existing = await 获取设置(env.DB, 'admin_pass');
    if (existing) return 响应JSON({ error: 'Already configured' }, 403);
    if (!body.password || body.password.length < 6) return 响应JSON({ error: 'Password too short' }, 400);
    await 更新设置(env.DB, 'admin_pass', body.password);
    const token = 哈希密码(body.password);
    return 响应JSON({ token, admin_path: await 获取设置(env.DB, 'admin_path') || 'login' });
  }

  // Public: login
  if (path === '/api/auth/login' && request.method === 'POST') {
    return await 处理登录(request, env);
  }

  // Auth check
  const cookie = request.headers.get('Cookie');
  const authHeader = request.headers.get('Authorization');
  let adminPass = env.ADMIN_PASS || '';
  try {
    const stored = await 获取设置(env.DB, 'admin_pass');
    if (stored) adminPass = stored;
  } catch {}

  let authenticated = false;
  if (authHeader && authHeader.startsWith('Bearer ')) {
    authenticated = authHeader.slice(7) === 哈希密码(adminPass);
  } else if (cookie) {
    const m = cookie.match(/usf_auth=([^;]+)/);
    if (m) authenticated = m[1] === 哈希密码(adminPass);
  }

  if (!authenticated) return 响应JSON({ error: 'Unauthorized' }, 401);

  if (path === '/api/dashboard' && request.method === 'GET') return await 处理仪表盘(env);
  if (path === '/api/users' && request.method === 'GET') return await 获取用户列表(env);
  if (path === '/api/users' && request.method === 'POST') return await 创建新用户(request, env);

  const userMatch = path.match(/^\/api\/users\/(\d+)(\/.*)?$/);
  if (userMatch) {
    const userId = parseInt(userMatch[1]);
    const sub = userMatch[2] || '';
    if (sub === '' && request.method === 'PUT') return await 修改用户(request, env, userId);
    if (sub === '' && request.method === 'DELETE') return await 删除用户调用(env, userId);
    if (sub === '/reset-traffic' && request.method === 'POST') return await 重置用户流量(env, userId);
    if (sub === '/connections' && request.method === 'GET') return await 获取用户连接(env, userId);
  }

  if (path === '/api/settings' && request.method === 'GET') {
    return 响应JSON(await 获取所有设置(env.DB));
  }
  if (path === '/api/settings' && request.method === 'PUT') return await 修改设置(request, env);
  if (path === '/api/change-password' && request.method === 'PUT') return await 修改密码(request, env);

  return 响应JSON({ error: 'Not found' }, 404);
}

async function 处理登录(request, env) {
  try {
    const body = await request.json();
    let adminPass = env.ADMIN_PASS || '';
    try {
      const stored = await 获取设置(env.DB, 'admin_pass');
      if (stored) adminPass = stored;
    } catch {}
    if (body.password === adminPass) {
      const token = 哈希密码(adminPass);
      return 响应JSON({ token, admin_path: await 获取设置(env.DB, 'admin_path') || 'login' });
    }
    return 响应JSON({ error: 'Invalid password' }, 401);
  } catch {
    return 响应JSON({ error: 'Bad request' }, 400);
  }
}

async function 处理仪表盘(env) {
  try {
    const stats = await 仪表盘统计(env.DB);
    const users = await 获取所有用户(env.DB);
    const recent = users.slice(0, 10).map(u => ({
      id: u.id, username: u.username, uuid: u.uuid,
      volume_used: u.volume_used, volume_limit: u.volume_limit,
      enabled: u.enabled, expire_date: u.expire_date, updated_at: u.updated_at,
    }));
    return 响应JSON({ ...stats, recent_users: recent });
  } catch (e) {
    return 响应JSON({ total_users: 0, active_users: 0, total_traffic: 0, active_connections: 0, recent_users: [] });
  }
}

async function 获取用户列表(env) {
  try {
    return 响应JSON({ users: await 获取所有用户(env.DB) });
  } catch (e) {
    return 响应JSON({ users: [] });
  }
}

async function 创建新用户(request, env) {
  try {
    const body = await request.json();
    if (!body.username || body.username.length < 3) return 响应JSON({ error: 'Username too short' }, 400);
    const existing = await 通过名称查找用户(env.DB, body.username);
    if (existing) return 响应JSON({ error: 'Username exists' }, 409);
    const uuid = 生成UUID();
    const password = 生成密码(16);
    const volLimit = (body.volume_limit || 0) * 1073741824;
    const user = await 创建用户(env.DB, uuid, body.username, password, volLimit, body.expire_days || 0, body.connection_limit || 0);
    if (body.note) await 更新用户(env.DB, user.id, { note: body.note });
    return 响应JSON({
      user: { ...user, volume_limit: user.volume_limit / 1073741824 },
      password,
      sub_link: '/' + (await 获取设置(env.DB, 'sub_path') || 's') + '/' + uuid,
    }, 201);
  } catch (e) {
    return 响应JSON({ error: e.message || 'Failed' }, 500);
  }
}

async function 修改用户(request, env, userId) {
  try {
    const body = await request.json();
    const updates = {};
    if (body.username !== undefined) updates.username = body.username;
    if (body.volume_limit !== undefined) updates.volume_limit = body.volume_limit * 1073741824;
    if (body.expire_days !== undefined) {
      if (body.expire_days === 0) { updates.expire_date = null; }
      else {
        const user = await 通过ID查找用户(env.DB, userId);
        const base = user ? new Date(user.created_at) : new Date();
        updates.expire_date = new Date(base.getTime() + body.expire_days * 86400000).toISOString();
      }
    }
    if (body.connection_limit !== undefined) updates.connection_limit = body.connection_limit;
    if (body.enabled !== undefined) updates.enabled = body.enabled ? 1 : 0;
    if (body.note !== undefined) updates.note = body.note;
    await 更新用户(env.DB, userId, updates);
    return 响应JSON({ success: true });
  } catch (e) {
    return 响应JSON({ error: e.message }, 500);
  }
}

