// ━━━ Subscription Page ━━━
async function 处理订阅页面(token, env, request) {
  const user = await 通过UUID查找用户(env.DB, token);
  if (!user) return new Response('Not found', { status: 404 });

  const url = new URL(request.url);
  const host = url.hostname;
  const settings = await 获取所有设置(env.DB);
  const subName = settings.sub_name || 'Usf-Edge';
  const subPath = settings.sub_path || 's';

  const totalUsed = user.volume_used || 0;
  const volumeLimit = user.volume_limit;
  const isUnlimited = volumeLimit <= 0;
  const volumePercent = isUnlimited ? 0 : Math.min(100, (totalUsed / volumeLimit) * 100);
  const daysLeft = 剩余天数(user.expire_date);
  const isExpired = daysLeft !== -1 && daysLeft <= 0;
  const isNever = daysLeft === -1;
  const activeConns = await 计算连接数(env.DB, user.id);
  const connLimit = user.connection_limit;

  let status = 'active';
  if (!user.enabled) status = 'disabled';
  else if (isExpired) status = 'expired';
  else if (!isUnlimited && volumePercent >= 100) status = 'limited';

  const baseURL = url.protocol + '//' + host;
  const subLink = baseURL + '/' + subPath + '/' + user.uuid;

  const connections = await 获取连接(env.DB, user.id);
  const connectionsJSON = JSON.stringify(connections.slice(0, 5).map(c => ({
    ip: c.ip_address, time: c.connected_at, ua: c.user_agent || 'Unknown'
  })));

  let html = 订阅页面;
  html = html.replace(/__USERNAME__/g, user.username);
  html = html.replace(/__SUB_NAME__/g, subName);
  html = html.replace(/__SUB_LINK__/g, subLink);
  html = html.replace(/__SUB_CLASH__/g, subLink + '?format=clash');
  html = html.replace(/__SUB_SINGBOX__/g, subLink + '?format=singbox');
  html = html.replace(/__SUB_V2RAY__/g, subLink + '?format=v2ray');
  html = html.replace(/__VOLUME_USED__/g, 格式化字节(totalUsed));
  html = html.replace(/__VOLUME_LIMIT__/g, isUnlimited ? 'Unlimited' : 格式化字节(volumeLimit));
  html = html.replace(/__VOLUME_PERCENT__/g, volumePercent.toFixed(1));
  html = html.replace(/__DAYS_REMAINING__/g, isNever ? '-1' : String(Math.max(0, daysLeft)));
  html = html.replace(/__EXPIRE_DATE__/g, isNever ? 'Never' : (user.expire_date ? new Date(user.expire_date).toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' }) : 'Never'));
  html = html.replace(/__ACTIVE_CONNS__/g, String(activeConns));
  html = html.replace(/__CONN_LIMIT__/g, connLimit <= 0 ? 'Unlimited' : String(connLimit));
  html = html.replace(/__STATUS__/g, status);
  html = html.replace(/__CONNECTIONS_JSON__/g, connectionsJSON);

  return new Response(html, { headers: { 'Content-Type': 'text/html; charset=utf-8' } });
}

// ━━━ Subscription Data ━━━
async function 处理订阅数据(token, env, request) {
  const user = await 通过UUID查找用户(env.DB, token);
  if (!user) return new Response('Not found', { status: 404 });

  const validation = await 验证用户访问(env.DB, user.uuid);
  if (!validation.allowed) return new Response('Subscription expired', { status: 403 });

  const url = new URL(request.url);
  let format = url.searchParams.get('format') || '';
  const ua = request.headers.get('User-Agent') || '';
  const host = url.hostname;
  const settings = await 获取所有设置(env.DB);
  const proto = settings.protocol || 协议名;
  const transport = settings.transport || 'ws';
  const path = (settings.path || '/');
  const wsPath = path.startsWith('/') ? path : '/' + path;
  const fingerprint = settings.fingerprint || 'chrome';
  const subName = settings.sub_name || 'Usf-Edge';
  const port = 443;

  if (!format) {
    const uaL = ua.toLowerCase();
    if (uaL.includes('clash') || uaL.includes('mihomo') || uaL.includes('meta')) format = 'clash';
    else if (uaL.includes('sing-box') || uaL.includes('sfm') || uaL.includes('sfa')) format = 'singbox';
    else format = 'v2ray';
  }

  if (format === 'clash') return 生成Clash配置(user, host, port, proto, transport, wsPath, fingerprint, subName);
  if (format === 'singbox') return 生成Singbox配置(user, host, port, proto, transport, wsPath, fingerprint, subName);

  const link = 生成链接(user, host, port, proto, transport, wsPath, fingerprint, subName);
  const b64 = btoa(link);
  const totalUsed = user.volume_used || 0;

  return new Response(b64, {
    headers: {
      'Content-Type': 'text/plain; charset=utf-8',
      'Content-Disposition': 'attachment; filename="' + subName + '.txt"',
      'Subscription-Userinfo': 'upload=' + Math.floor(totalUsed/2) + '; download=' + Math.floor(totalUsed/2) + '; total=' + (user.volume_limit > 0 ? user.volume_limit : 0) + '; expire=' + (user.expire_date ? new Date(user.expire_date).getTime()/1000 : 0),
      'Profile-Update-Interval': '6',
      'Profile-Title': subName,
    },
  });
}

function 生成链接(user, host, port, proto, transport, path, fp, subName) {
  const params = new URLSearchParams({ type: transport, security: 'tls', fingerprint: fp, sni: host, path });
  if (transport === 'grpc') { params.set('serviceName', 'grpc'); params.delete('path'); }
  const prefix = proto === 隧道名 ? 隧道名 : 协议名;
  return prefix + '://' + user.uuid + '@' + host + ':' + port + '?' + params.toString() + '#' + encodeURIComponent(subName + ' - ' + user.username);
}

function 生成Clash配置(user, host, port, proto, transport, path, fp, subName) {
  let lines = ['proxies:', '- name: "' + subName + ' - ' + user.username + '"'];
  if (proto === 隧道名) {
    lines.push('  type: trojan', '  server: ' + host, '  port: ' + port, '  password: "' + user.uuid + '"');
  } else {
    lines.push('  type: vless', '  server: ' + host, '  port: ' + port, '  uuid: "' + user.uuid + '"');
  }
  lines.push('  tls: true', '  servername: ' + host, '  client-fingerprint: ' + fp);
  if (transport === 'ws') {
    lines.push('  network: ws', '  ws-opts:', '    path: ' + path, '    headers:', '      Host: ' + host);
  } else if (transport === 'grpc') {
    lines.push('  network: grpc', '  grpc-opts:', '    grpc-service-name: grpc');
  }
  return new Response(lines.join('\n') + '\n', {
    headers: { 'Content-Type': 'text/yaml; charset=utf-8', 'Subscription-Userinfo': 'upload=0; download=0; total=' + (user.volume_limit > 0 ? user.volume_limit : 0) }
  });
}

function 生成Singbox配置(user, host, port, proto, transport, path, fp, subName) {
  let tc = '';
  if (transport === 'ws') tc = ', "transport": { "type": "ws", "path": "' + path + '", "headers": { "Host": "' + host + '" } }';
  else if (transport === 'grpc') tc = ', "transport": { "type": "grpc", "service_name": "grpc" }';
  const tls = ', "tls": { "enabled": true, "server_name": "' + host + '", "utls": { "enabled": true, "fingerprint": "' + fp + '" } }';
  const t = proto === 隧道名 ? 'trojan' : 'vless';
  const idField = proto === 隧道名 ? '"password": "' + user.uuid + '"' : '"uuid": "' + user.uuid + '"';
  const outbound = JSON.parse('{ "type": "' + t + '", "tag": "' + subName + ' - ' + user.username + '", "server": "' + host + '", "server_port": ' + port + ', ' + idField + tls + tc + ' }');
  return new Response(JSON.stringify({ outbounds: [outbound] }, null, 2), {
    headers: { 'Content-Type': 'application/json; charset=utf-8', 'Subscription-Userinfo': 'upload=0; download=0; total=' + (user.volume_limit > 0 ? user.volume_limit : 0) }
  });
}


// ━━━ Main Worker Export ━━━
export default {
  async fetch(request, env, ctx) {
    try {
      const url = new URL(request.url);

      let adminPath = 'login';
      let subPath = 's';
      try {
        const ap = await 获取设置(env.DB, 'admin_path');
        if (ap) adminPath = ap;
        const sp = await 获取设置(env.DB, 'sub_path');
        if (sp) subPath = sp;
      } catch {}

      const pathname = url.pathname;

      // Block speedtest
      const ua = request.headers.get('User-Agent') || '';
      if (ua.toLowerCase().includes('speedtest') || ua.toLowerCase().includes('speed')) {
        return new Response(null, { status: 444 });
      }

      // Admin panel
      if (pathname === '/' + adminPath || pathname === '/' + adminPath + '/') {
        const html = 管理页面.replace(/__ADMIN_API__/g, '/' + adminPath + '/api');
        return new Response(html, {
          headers: { 'Content-Type': 'text/html; charset=utf-8', ...禁止缓存 },
        });
      }

      // Admin API
      if (pathname.startsWith('/' + adminPath + '/api/')) {
        const apiPath = pathname.slice('/' + adminPath.length);
        return 处理管理API(request, env, apiPath);
      }

      // Subscription page or data
      const subRegex = new RegExp('^/' + subPath + '/([a-f0-9-]{36})$');
      const subMatch = pathname.match(subRegex);
      if (subMatch) {
        if (url.searchParams.has('format')) {
          return 处理订阅数据(subMatch[1], env, request);
        }
        return 处理订阅页面(subMatch[1], env, request);
      }

      // Version
      if (pathname === '/version') {
        return new Response(JSON.stringify({ name: 'Usf-Edge', version: '1.0.0' }), {
          headers: { 'Content-Type': 'application/json' },
        });
      }

      // Try proxy handler
      const proxyResult = await 代理处理(request, env);
      if (proxyResult) return proxyResult;

      // Stealth fake page
      return new Response(伪装页面, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      });
    } catch (e) {
      return new Response(JSON.stringify({ error: e.message || 'Internal error' }), {
        status: 500, headers: { 'Content-Type': 'application/json' },
      });
    }
  },
};
